/// Declarative config for a standard 3D ray-marched fractal.
///
/// Adding a new ray-marched 3D fractal = one [Raymarched3DConfig] + one .frag shader.
/// No separate Dart module file needed.
///
/// All 3D ray-marched fractals share this uniform layout (matching mandelbulb.frag):
///   float 0:  uTime
///   float 1-2: uResolution (vec2)
///   float 3-4: uMousePos (vec2, unused placeholder)
///   float 5:  uZoom
///   float 6-8: uRotation (vec3)
///   float 9:  uPower
///   float 10: uIterations
///   float 11: uSteps
///   float 12: uBailout
///   float 13: uColorScheme
///   float 14: uFractalType
///   float 15: uTransparentBg
class Raymarched3DConfig {
  final String id;
  final String name;
  final ModuleNameBuilder? displayName;
  final String shaderAsset;
  final String category;

  // Default parameter values
  final double defaultPower;
  final double minPower;
  final double maxPower;
  final String powerLabel;
  final double defaultIterations;
  final double maxIterations;
  final double defaultSteps;
  final double defaultBailout;
  final int defaultColorScheme;
  final int maxColorScheme;
  final int defaultFractalType;
  final int maxFractalType;
  final List<FractalParamOption> fractalTypeOptions;
  final List<FractalPreset> extraPresets;

  const Raymarched3DConfig({
    required this.id,
    required this.name,
    required this.shaderAsset,
    this.displayName,
    this.category = '3D Fractals',
    this.defaultPower = 8.0,
    this.minPower = 2.0,
    this.maxPower = 12.0,
    this.powerLabel = 'Power',
    this.defaultIterations = 50,
    this.maxIterations = 100,
    this.defaultSteps = 120,
    this.defaultBailout = 2.0,
    this.defaultColorScheme = 0,
    this.maxColorScheme = 3,
    this.defaultFractalType = 0,
    this.maxFractalType = 0,
    this.fractalTypeOptions = const [],
    this.extraPresets = const [],
  });
}

/// Builds a [FractalModule] from a declarative [Raymarched3DConfig].
FractalModule buildRaymarched3DModule(Raymarched3DConfig config) {
  final parameters = [
    FractalParameter(
      id: 'power',
      label: (_) => config.powerLabel,
      type: FractalParamType.float,
      min: config.minPower,
      max: config.maxPower,
      step: 0.1,
      defaultValue: config.defaultPower,
    ),
    CommonFractalParams.iterations(
      defaultValue: config.defaultIterations,
      min: 5,
      max: config.maxIterations,
    ),
    FractalParameter(
      id: 'steps',
      label: (l10n) => l10n.paramSteps,
      type: FractalParamType.integer,
      min: 20,
      max: 200,
      step: 1,
      defaultValue: config.defaultSteps,
    ),
    CommonFractalParams.bailout(
      defaultValue: config.defaultBailout,
      min: 1.0,
      max: 8.0,
    ),
    CommonFractalParams.colorScheme4(
      defaultValue: config.defaultColorScheme.toDouble(),
      max: config.maxColorScheme,
    ),
    if (config.maxFractalType > 0)
      FractalParameter(
        id: 'fractalType',
        label: (_) => 'Variant',
        type: FractalParamType.enumeration,
        min: 0,
        max: config.maxFractalType.toDouble(),
        step: 1,
        defaultValue: config.defaultFractalType.toDouble(),
        options: config.fractalTypeOptions,
      ),
  ];

  final defaultParams = <String, Object>{
    'power': config.defaultPower,
    'iterations': config.defaultIterations,
    'steps': config.defaultSteps,
    'bailout': config.defaultBailout,
    'colorScheme': config.defaultColorScheme,
    if (config.maxFractalType > 0) 'fractalType': config.defaultFractalType,
  };

  final defaultPreset = FractalPreset(
    id: '${config.id}-default',
    moduleId: config.id,
    name: 'Default',
    params: defaultParams,
    view: FractalViewState(
      pan: Vector2.zero(),
      zoom: 1.0,
      rotation: Vector3(0.3, -0.4, 0.0),
    ),
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );

  return FractalModule(
    id: config.id,
    displayName: config.displayName ?? ((_) => config.name),
    dimension: FractalDimension.threeD,
    shaderAsset: config.shaderAsset,
    parameters: parameters,
    defaultPreset: defaultPreset,
    builtInPresets: buildBuiltInPresetList(
      moduleId: config.id,
      defaultPreset: defaultPreset,
      extraPresets: config.extraPresets,
    ),
    setUniforms: (shader, state, size, time) {
      shader.setFloat(Raymarched3DUniformSlots.time, time);
      shader.setFloat(Raymarched3DUniformSlots.resolutionX, size.width);
      shader.setFloat(Raymarched3DUniformSlots.resolutionY, size.height);
      shader.setFloat(Raymarched3DUniformSlots.mouseX, 0.0); // unused
      shader.setFloat(Raymarched3DUniformSlots.mouseY, 0.0); // unused
      shader.setFloat(Raymarched3DUniformSlots.zoom, state.view.zoom);
      shader.setFloat(
          Raymarched3DUniformSlots.rotationX, state.view.rotation.x);
      shader.setFloat(
          Raymarched3DUniformSlots.rotationY, state.view.rotation.y);
      shader.setFloat(
          Raymarched3DUniformSlots.rotationZ, state.view.rotation.z);
      shader.setFloat(Raymarched3DUniformSlots.power,
          readDouble(state.params, 'power', config.defaultPower));
      shader.setFloat(Raymarched3DUniformSlots.iterations,
          readDouble(state.params, 'iterations', config.defaultIterations));
      shader.setFloat(Raymarched3DUniformSlots.steps,
          readDouble(state.params, 'steps', config.defaultSteps));
      shader.setFloat(Raymarched3DUniformSlots.bailout,
          readDouble(state.params, 'bailout', config.defaultBailout));
      shader.setFloat(
          Raymarched3DUniformSlots.colorScheme,
          readDouble(state.params, 'colorScheme',
              config.defaultColorScheme.toDouble()));
      shader.setFloat(
          Raymarched3DUniformSlots.fractalType,
          readDouble(state.params, 'fractalType',
              config.defaultFractalType.toDouble()));
      shader.setFloat(Raymarched3DUniformSlots.transparentBackground,
          state.transparentBackground ? 1.0 : 0.0);
    },
  );
}

import 'package:flutter_fractals/core/models/fractal_preset.dart';

/// Stable provenance marker for generated built-in presets.
///
/// Builder-owned presets are part of the app catalog, not user-created data, so
/// their metadata must be replayable across registry rebuilds and test runs.
final builtInPresetCreatedAt = DateTime.utc(2025, 1, 1);

/// Returns the builder-facing built-in preset list with replayable metadata.
///
/// Catalog entries often provide curated [extraPresets] for params/view only.
/// Normalize them here so callers cannot accidentally surface mutable-looking,
/// non-replayable, or stale-module presets in [FractalModule.builtInPresets].
List<FractalPreset> buildBuiltInPresetList({
  required String moduleId,
  required FractalPreset defaultPreset,
  required List<FractalPreset> extraPresets,
}) {
  assert(moduleId.isNotEmpty, 'Built-in presets require a module id.');
  assert(
    defaultPreset.moduleId == moduleId,
    'Default built-in preset moduleId must match its module.',
  );

  final usedIds = <String>{};
  return [
    _asReplayableBuiltInPreset(
      defaultPreset.copyWith(id: '$moduleId-classic', name: 'Classic'),
      moduleId,
      usedIds,
    ),
    ...extraPresets.map((preset) => _asReplayableBuiltInPreset(
          preset,
          moduleId,
          usedIds,
        )),
  ];
}

FractalPreset _asReplayableBuiltInPreset(
  FractalPreset preset,
  String moduleId,
  Set<String> usedIds,
) {
  return preset.copyWith(
    id: _uniquePresetId(preset.id, usedIds),
    moduleId: moduleId,
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );
}

String _uniquePresetId(String id, Set<String> usedIds) {
  if (usedIds.add(id)) return id;

  var suffix = 2;
  while (true) {
    final candidate = '$id-$suffix';
    if (usedIds.add(candidate)) return candidate;
    suffix++;
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';

void main() {
  group('CommonFractalParams', () {
    test(
        'builds standard escape-time iteration parameter without changing schema',
        () {
      final parameter = CommonFractalParams.iterations(defaultValue: 160);

      expect(parameter.id, 'iterations');
      expect(parameter.type, FractalParamType.integer);
      expect(parameter.min, 20);
      expect(parameter.max, 5000);
      expect(parameter.step, 1);
      expect(parameter.defaultValue, 160);
    });

    test(
        'builds standard escape-time bailout parameter without changing schema',
        () {
      final parameter = CommonFractalParams.bailout(defaultValue: 4.0);

      expect(parameter.id, 'bailout');
      expect(parameter.type, FractalParamType.float);
      expect(parameter.min, 2.0);
      expect(parameter.max, 8.0);
      expect(parameter.step, 0.1);
      expect(parameter.defaultValue, 4.0);
    });

    test(
        'builds four-palette 3D color scheme parameter without changing options',
        () {
      final parameter = CommonFractalParams.colorScheme4(defaultValue: 0);

      expect(parameter.id, 'colorScheme');
      expect(parameter.type, FractalParamType.enumeration);
      expect(parameter.min, 0);
      expect(parameter.max, 3);
      expect(parameter.step, 1);
      expect(parameter.defaultValue, 0);
      expect(parameter.options.map((option) => option.value), [0, 1, 2, 3]);
    });
  });
}

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/core/modules/param_reader.dart';

void main() {
  group('readDouble', () {
    test('accepts finite int and double values', () {
      expect(readDouble({'power': 8}, 'power', 2.0), 8.0);
      expect(readDouble({'power': 3.5}, 'power', 2.0), 3.5);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readDouble(const {}, 'power', 2.0), 2.0);
      expect(readDouble({'power': '8'}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.nan}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.infinity}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.negativeInfinity}, 'power', 2.0), 2.0);
    });
  });

  group('readInt', () {
    test('accepts integer values and rounds finite doubles', () {
      expect(readInt({'iterations': 120}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.4}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.5}, 'iterations', 80), 121);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readInt(const {}, 'iterations', 80), 80);
      expect(readInt({'iterations': '120'}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.nan}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.infinity}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.negativeInfinity}, 'iterations', 80),
          80);
    });

    test('falls back for finite doubles outside integer range', () {
      expect(readInt({'iterations': 1e100}, 'iterations', 80), 80);
      expect(readInt({'iterations': -1e100}, 'iterations', 80), 80);
    });
  });
}

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu_viewport_mapping.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

void main() {
  group('CPU viewport mapping', () {
    test('subpixel samples stay inside the normalized viewport', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(-0.5, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(0.5, 1e-12),
      );
    });

    test('invalid subpixel sample candidates clamp to the pixel footprint', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 4,
          samplesPerAxis: 2,
        ),
        closeTo(0.75, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: -1,
          samplesPerAxis: 2,
        ),
        closeTo(-0.75, 1e-12),
      );
    });

    test('edge pixels preserve iteration-buffer edge-inclusive contract', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(viewport.normalizedPixel(0, 2), -1.0);
      expect(viewport.normalizedPixel(1, 2), 1.0);
    });

    test('invalid zoom falls back to replayable unit-scale coordinates', () {
      for (final zoom in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        final viewport = CpuViewportMapping(
          viewPan: Vector2.zero(),
          viewZoom: zoom,
          width: 2,
          height: 2,
        );

        expect(viewport.scale, 1.5, reason: 'zoom=$zoom');
        expect(
          viewport.coordinate(nx: 0.5, ny: -0.5),
          (0.75, -0.75),
          reason: 'zoom=$zoom',
        );
      }
    });

    test('invalid pan falls back to the replayable origin center', () {
      for (final pan in [
        Vector2(double.nan, 0.25),
        Vector2(double.infinity, double.negativeInfinity),
      ]) {
        final center = CpuViewportCenter.fromScalars(
          panX: pan.x,
          panY: pan.y,
        );
        final viewport = CpuViewportMapping(
          viewPan: pan,
          viewZoom: 1.0,
          width: 2,
          height: 2,
        );
        final expectedY = pan.y.isFinite ? pan.y : 0.0;

        expect(center.x, 0.0, reason: 'pan=$pan');
        expect(center.y, expectedY, reason: 'pan=$pan');
        expect(viewport.centerX, center.x, reason: 'pan=$pan');
        expect(viewport.centerY, center.y, reason: 'pan=$pan');
        expect(
          viewport.coordinate(nx: 0.5, ny: -0.5),
          (0.75, expectedY - 0.75),
          reason: 'pan=$pan',
        );
      }
    });

    test('invalid viewport dimensions fall back to square aspect', () {
      expect(
        CpuViewportDimensions.fromSize(width: 0, height: 2).aspect,
        1.0,
      );
      expect(
        CpuViewportDimensions.fromSize(width: 2, height: -1).aspect,
        1.0,
      );

      final zeroWidthViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 0,
        height: 2,
      );
      final negativeHeightViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: -1,
      );

      expect(zeroWidthViewport.coordinate(nx: 0.5, ny: -0.5), (0.75, -0.75));
      expect(
        negativeHeightViewport.coordinate(nx: 0.5, ny: -0.5),
        (0.75, -0.75),
      );
    });

    test('iteration buffer shares CPU render dimension validation', () async {
      await expectLater(
        renderCpuIterationBuffer(
          moduleId: 'mandelbrot',
          viewPan: Vector2.zero(),
          viewZoom: 1.0,
          iterations: 50,
          bailout: 4.0,
          juliaC: Vector2(-0.8, 0.156),
          width: 0,
          height: 2,
        ),
        throwsArgumentError,
      );

      await expectLater(
        renderCpuIterationBuffer(
          moduleId: 'mandelbrot',
          viewPan: Vector2.zero(),
          viewZoom: 1.0,
          iterations: 50,
          bailout: 4.0,
          juliaC: Vector2(-0.8, 0.156),
          width: 2,
          height: -1,
        ),
        throwsArgumentError,
      );
    });

    test('isolate sample mapping shares invalid zoom normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: 0.0,
        panY: 0.0,
        zoom: double.nan,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('isolate sample mapping shares invalid pan normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: double.nan,
        panY: double.infinity,
        zoom: 1.0,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('anti-aliasing grid makes non-square sample counts replayable', () {
      expect(CpuSampleGrid.fromRequestedCount(-1).samplesPerAxis, 1);
      expect(CpuSampleGrid.fromRequestedCount(1).totalSamples, 1);
      expect(CpuSampleGrid.fromRequestedCount(4).totalSamples, 4);
      expect(CpuSampleGrid.fromRequestedCount(8).samplesPerAxis, 3);
      expect(CpuSampleGrid.fromRequestedCount(8).totalSamples, 9);
    });

    test('anti-aliasing grid never drops requested multisample candidates', () {
      for (final requestedCount in [2, 3, 5, 6, 7, 8]) {
        final grid = CpuSampleGrid.fromRequestedCount(requestedCount);

        expect(
          grid.totalSamples,
          greaterThanOrEqualTo(requestedCount),
          reason: 'requestedCount=$requestedCount',
        );
        expect(grid.requestedCount, requestedCount);
        expect(grid.wasRoundedUp, isTrue);
      }
    });

    test('single-pixel iteration buffer samples the viewport center', () async {
      final buffer = await renderCpuIterationBuffer(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.5, 0.0),
        viewZoom: 1.0,
        iterations: 50,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: 1,
        height: 1,
      );

      expect(buffer, isNotNull);
      expect(buffer!.single, 50);
    });
  });
}

import 'package:flutter_fractals/features/renderer/cpu_iteration_budget.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CpuIterationBudget', () {
    test('preserves zoom-depth iteration scaling contract', () {
      expect(
        CpuIterationBudget.forZoom(
          baseIterations: 120,
          maxIterations: 500,
          zoom: 1.0,
        ),
        120,
      );
      expect(
        CpuIterationBudget.forZoom(
          baseIterations: 120,
          maxIterations: 500,
          zoom: 4.0,
        ),
        184,
      );
      expect(
        CpuIterationBudget.forZoom(
          baseIterations: 490,
          maxIterations: 500,
          zoom: 4.0,
        ),
        500,
      );
    });

    test('normalizes malformed zoom samples before log/round', () {
      for (final zoom in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
        0.0,
        -2.0,
      ]) {
        expect(
          CpuIterationBudget.normalizeZoom(zoom),
          1.0,
          reason: 'zoom=$zoom',
        );
        expect(
          CpuIterationBudget.forZoom(
            baseIterations: 120,
            maxIterations: 500,
            zoom: zoom,
          ),
          120,
          reason: 'zoom=$zoom',
        );
      }
    });

    test('keeps the minimum iteration floor replayable', () {
      expect(
        CpuIterationBudget.forZoom(
          baseIterations: 1,
          maxIterations: 10,
          zoom: 1.0,
        ),
        CpuIterationBudget.minimumIterations,
      );
    });
  });
}

import 'dart:typed_data';

import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

/// Builds a Uint8List RGBA frame of [w]x[h] pixels, all zeroed (black).
Uint8List _blackFrame(int w, int h) => Uint8List(w * h * 4);

/// Pixel index for (x, y) in a [w]-wide RGBA frame.
int _px(int x, int y, int w) => (y * w + x) * 4;

void main() {
  group('RenderValidationThresholds', () {
    test('exposes default health thresholds as replayable comparisons', () {
      const thresholds = RenderValidationThresholds.defaults;

      expect(thresholds.blackThreshold, 8);
      expect(thresholds.differenceThreshold, 12);
      expect(thresholds.minimumNonBlackRatio, 0.01);
      expect(thresholds.minimumProgressionRatio, 0.002);
      expect(thresholds.minimumIterationDeltaRatio, 0.01);

      expect(thresholds.isNonBlackPixel(8, 8, 8), isFalse);
      expect(thresholds.isNonBlackPixel(9, 0, 0), isTrue);
      expect(
        thresholds.isVisiblyDifferent(
          rA: 0,
          gA: 0,
          bA: 0,
          rB: 4,
          gB: 4,
          bB: 4,
        ),
        isFalse,
      );
      expect(
        thresholds.isVisiblyDifferent(
          rA: 0,
          gA: 0,
          bA: 0,
          rB: 5,
          gB: 4,
          bB: 4,
        ),
        isTrue,
      );
      expect(thresholds.histogramSaneFor(0.01), isFalse);
      expect(thresholds.histogramSaneFor(0.0101), isTrue);
      expect(thresholds.frameProgressedFor(0.002), isFalse);
      expect(thresholds.frameProgressedFor(0.0021), isTrue);
      expect(thresholds.iterationDeltaVisibleFor(0.01), isFalse);
      expect(thresholds.iterationDeltaVisibleFor(0.0101), isTrue);
    });
  });

  group('sampleRenderCenter', () {
    test('exposes even-dimension center sampling and black fallback', () {
      final frame = _blackFrame(4, 4);
      final idx = _px(2, 2, 4);
      frame[idx] = 100;
      frame[idx + 1] = 120;
      frame[idx + 2] = 140;

      final center = sampleRenderCenter(frame: frame, width: 4, height: 4);
      final truncatedCenter = sampleRenderCenter(
        frame: Uint8List(4),
        width: 4,
        height: 4,
      );

      expect(center.readable, isTrue);
      expect(center.r, 100);
      expect(center.g, 120);
      expect(center.b, 140);
      expect(center.nonBlack, isTrue);
      expect(truncatedCenter.readable, isFalse);
      expect(truncatedCenter.r, 0);
      expect(truncatedCenter.g, 0);
      expect(truncatedCenter.b, 0);
      expect(truncatedCenter.nonBlack, isFalse);
    });
  });

  group('sampleRenderFrame', () {
    test('exposes readable pixel counts for truncated frames', () {
      final frame = _blackFrame(3, 1);
      frame[0] = 80;
      frame[4] = 80;

      final sample = sampleRenderFrame(frame: frame, width: 4, height: 2);

      expect(sample.totalPixels, 8);
      expect(sample.readablePixels, 3);
      expect(sample.nonBlackPixels, 2);
      expect(sample.centerReadable, isFalse);
      expect(sample.hasCompleteFrame, isFalse);
      expect(sample.nonBlackRatio, 2 / 8);
    });
  });

  group('sampleRenderPair', () {
    test('exposes comparable pixels and gates progression on complete pairs',
        () {
      final frameA = _blackFrame(2, 1);
      final frameB = _blackFrame(3, 1);
      frameB[0] = 80;
      frameB[4] = 80;
      frameB[8] = 80;

      final sample = sampleRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 3,
        height: 1,
      );

      expect(sample.frameB.totalPixels, 3);
      expect(sample.frameB.readablePixels, 3);
      expect(sample.comparablePixels, 2);
      expect(sample.differentPixels, 2);
      expect(sample.hasCompletePair, isFalse);
      expect(sample.progressionRatio, 0.0);
    });
  });

  group('validateRenderFrame', () {
    test('empty dimensions return invalid black stats instead of crashing', () {
      final stats = validateRenderFrame(
        frame: Uint8List(0),
        width: 0,
        height: 0,
      );

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('negative dimensions are treated as invalid frame geometry', () {
      final frame = _blackFrame(1, 1);
      frame[0] = 80;
      frame[1] = 80;
      frame[2] = 80;

      final stats = validateRenderFrame(
        frame: frame,
        width: -1,
        height: -1,
      );

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects all-black frame', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects non-black center pixel', () {
      final frame = _blackFrame(4, 4);
      // center of 4x4 is floor(2), floor(2) = (2,2)
      final idx = _px(2, 2, 4);
      frame[idx] = 100;
      frame[idx + 1] = 150;
      frame[idx + 2] = 200;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 100);
      expect(stats.centerG, 150);
      expect(stats.centerB, 200);
      expect(stats.centerNonBlack, isTrue);
    });

    test('calculates correct nonBlackRatio', () {
      // 8 pixels total; make exactly 4 non-black
      final frame = _blackFrame(4, 2);
      // pixels at (0,0),(1,0),(2,0),(3,0) — first row, r=20 > 8 threshold
      for (int col = 0; col < 4; col++) {
        frame[_px(col, 0, 4)] = 20;
      }
      final stats = validateRenderFrame(frame: frame, width: 4, height: 2);

      expect(stats.nonBlackRatio, closeTo(4 / 8, 1e-9));
    });

    test('histogramSane is false when ratio <= 0.01', () {
      // 100 pixels, only 1 non-black => ratio = 0.01 which is NOT > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.01, 1e-9));
      expect(stats.histogramSane, isFalse);
    });

    test('histogramSane is true when ratio > 0.01', () {
      // 100 pixels, 2 non-black => ratio = 0.02 > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      frame[4] = 20; // next pixel (x=1,y=0)
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.02, 1e-9));
      expect(stats.histogramSane, isTrue);
    });

    test('summary includes backend name', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      final summary = stats.summary('gpu');

      expect(summary, contains('backend=gpu'));
      expect(summary, contains('[renderer]'));
      expect(summary, contains('non_black_ratio='));
      expect(summary, contains('histogram_sane='));
    });

    test('boundary: threshold pixel value of 8 is still counted as black', () {
      final frame = _blackFrame(4, 4);
      // Set center pixel RGB all to exactly 8 — threshold is > 8, so this is black
      final idx = _px(2, 2, 4);
      frame[idx] = 8;
      frame[idx + 1] = 8;
      frame[idx + 2] = 8;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isFalse);
    });

    test('boundary: pixel value of 9 is counted as non-black', () {
      final frame = _blackFrame(4, 4);
      final idx = _px(2, 2, 4);
      frame[idx] = 9;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isTrue);
    });
  });

  group('validateRenderPair', () {
    test('empty dimensions return failed check instead of crashing', () {
      final result = validateRenderPair(
        frameA: Uint8List(0),
        frameB: Uint8List(0),
        width: 0,
        height: 0,
      );

      expect(result.centerR, 0);
      expect(result.centerG, 0);
      expect(result.centerB, 0);
      expect(result.centerNonBlack, isFalse);
      expect(result.histogramSane, isFalse);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('negative dimensions cannot pass from readable single-pixel frames',
        () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(1, 1);
      frameB[0] = 80;
      frameB[1] = 80;
      frameB[2] = 80;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: -1,
        height: -1,
      );

      expect(result.centerR, 0);
      expect(result.centerG, 0);
      expect(result.centerB, 0);
      expect(result.centerNonBlack, isFalse);
      expect(result.nonBlackRatio, 0.0);
      expect(result.histogramSane, isFalse);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('detects frame progression when enough pixels differ', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);

      // Make every pixel differ significantly (dr+dg+db > 12)
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 50;
        frameB[i + 1] = 50;
        frameB[i + 2] = 50;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });

    test('frameProgressed is false when frames are identical', () {
      final frameA = _blackFrame(4, 4);
      final frameB = Uint8List.fromList(frameA);

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('iterationDeltaVisible requires > 1% different pixels', () {
      // 100 pixels total; need > 1 different pixel for iterationDeltaVisible
      // Exactly 1 different pixel => 1% which is NOT > 0.01
      final frameA = _blackFrame(10, 10);
      final frameB = Uint8List.fromList(frameA);
      frameB[0] = 100;
      frameB[1] = 100;
      frameB[2] = 100;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      // progressionRatio = 1/100 = 0.01; frameProgressed needs > 0.002 (true)
      expect(result.frameProgressed, isTrue);
      // iterationDeltaVisible needs > 0.01 (false — exactly 0.01)
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('uses frameB readable pixels for histogram when frameA is truncated',
        () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(10, 10);

      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 80;
        frameB[i + 1] = 80;
        frameB[i + 2] = 80;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.nonBlackRatio, 1.0);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('does not report progression from incomplete frame pairs', () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(1, 1);
      frameB[0] = 80;
      frameB[1] = 80;
      frameB[2] = 80;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('pass is true only when all checks pass', () {
      // Build a 10x10 frame where enough pixels are non-black and different
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Fill all pixels in frameB with colour that exceeds all thresholds
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 80;
        frameB[i + 1] = 80;
        frameB[i + 2] = 80;
        frameB[i + 3] = 255;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
      expect(result.pass, isTrue);
    });

    test('pass is false when centerNonBlack is false', () {
      // Non-zero progression but center stays black
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Colour many pixels except the center (5,5)
      for (int row = 0; row < 10; row++) {
        for (int col = 0; col < 10; col++) {
          if (row == 5 && col == 5) continue;
          final i = _px(col, row, 10);
          frameB[i] = 80;
          frameB[i + 1] = 80;
          frameB[i + 2] = 80;
        }
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isFalse);
      expect(result.pass, isFalse);
    });

    test('handles all-identical frames — no progression', () {
      final frameA = Uint8List.fromList(List.filled(20 * 20 * 4, 50));
      final frameB = Uint8List.fromList(List.filled(20 * 20 * 4, 50));

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 20,
        height: 20,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('summary includes pass status and backend name', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);
      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );
      final summary = result.summary('cpu');

      expect(summary, contains('backend=cpu'));
      expect(summary, contains('pass='));
      expect(summary, contains('[renderer]'));
    });
  });
}

import 'dart:async';
import 'dart:typed_data';
import 'dart:ui' as ui;

import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/param_reader.dart';
import '../validation/render_validation.dart';
import '../validation/convergence_detector.dart';
import 'cpu_render_isolate.dart';
import 'cpu_tile_worker.dart';
import 'cpu_iteration_budget.dart';
import 'cpu_iterators.dart';
import 'cpu_render_resolution.dart';
import 'cpu_viewport_mapping.dart';

/// Very small CPU fallback renderer for 2D fractals.
///
/// Deep-zoom quality path:
/// - Uses double-precision math on CPU for stable deep zoom coordinates.
/// - Uses multi-sample anti-aliasing (2x2) to reduce grain/noise.
/// - Uses smooth/continuous escape-time coloring.
class CpuFractalRenderer extends StatefulWidget {
  final FractalModule module;
  final FractalRenderState state;

  /// Target render resolution (will be scaled to fit).
  final int width;
  final int height;

  /// Called when a partial CPU frame is available.
  final VoidCallback? onPartial;

  /// Called when slow mode active state changes.
  final ValueChanged<bool>? onSlowModeActiveChanged;

  const CpuFractalRenderer({
    super.key,
    required this.module,
    required this.state,
    this.width = 360,
    this.height = 360,
    this.onPartial,
    this.onSlowModeActiveChanged,
  });

  @override
  State<CpuFractalRenderer> createState() => _CpuFractalRendererState();
}

class _CpuFractalRendererState extends State<CpuFractalRenderer> {
  ui.Image? _image;
  Object? _error;
  int _job = 0;
  Timer? _debounce;
  Timer? _refineTimer;
  RenderCheckResult? _lastValidation;

  // Convergence detection for adaptive iteration adjustment.
  final ConvergenceDetector _convergenceDetector = const ConvergenceDetector();
  Uint8List? _previousFrameBuffer;
  bool _isConverged = false;

  CpuTileWorker? _worker;

  int? _slowModeRow;
  int? _slowModeTotal;
  bool _slowModeActive = false;

  // Preview vs refine rendering.
  DateTime? _lastInteractionAt;

  @override
  void initState() {
    super.initState();
    _spawnWorker();
  }

  Future<void> _spawnWorker() async {
    try {
      _worker = await CpuTileWorker.spawn();
      if (!mounted) {
        _worker?.dispose();
        return;
      }
      _scheduleRender();
    } catch (e) {
      if (mounted) setState(() => _error = e);
    }
  }

  @override
  void didUpdateWidget(covariant CpuFractalRenderer oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.module.id != widget.module.id ||
        oldWidget.state.view.zoom != widget.state.view.zoom ||
        oldWidget.state.view.pan != widget.state.view.pan ||
        oldWidget.state.params != widget.state.params) {
      _markInteraction();
      _scheduleRender();
    }
  }

  @override
  void dispose() {
    _debounce?.cancel();
    _refineTimer?.cancel();
    _setSlowModeActive(false);
    _worker?.dispose();
    _image?.dispose();
    super.dispose();
  }

  void _markInteraction() {
    _lastInteractionAt = DateTime.now();
    // Reset convergence state on new interaction.
    _isConverged = false;
  }

  /// Checks frame-to-frame convergence and updates iteration budget.
  /// Returns adjusted iteration count based on convergence result.
  int _checkConvergence(
      Uint8List currentBuffer, int width, int height, int currentIterations) {
    final prev = _previousFrameBuffer;

    if (prev == null || prev.length != currentBuffer.length) {
      // First frame - store and return current iterations.
      _previousFrameBuffer = Uint8List.fromList(currentBuffer);
      _isConverged = false;
      return currentIterations;
    }

    // Compare with previous frame.
    final result = _convergenceDetector.detect(
      previous: prev,
      current: currentBuffer,
      width: width,
      height: height,
      currentIterations: currentIterations,
    );

    // Store current buffer for next comparison.
    _previousFrameBuffer = Uint8List.fromList(currentBuffer);
    _isConverged = result.converged;

    // Log convergence state in debug mode.
    if (kDebugMode && result.changeRatio > 0.01) {
      debugPrint('[cpu] convergence: converged=${result.converged} '
          'change=${(result.changeRatio * 100).toStringAsFixed(1)}% '
          'iter=$currentIterations->${result.suggestedIterations}');
    }

    // Use suggested iterations for next render if not converged.
    return result.suggestedIterations.clamp(50, _iterationMaxForModule());
  }

  bool _shouldStillBeInteracting() {
    final t = _lastInteractionAt;
    if (t == null) return false;
    return DateTime.now().difference(t) < const Duration(milliseconds: 220);
  }

  void _scheduleRender() {
    _debounce?.cancel();
    _debounce = Timer(const Duration(milliseconds: 60), _renderPreview);

    // Schedule a refine pass after user stops touching.
    _refineTimer?.cancel();
    _refineTimer = Timer(const Duration(milliseconds: 260), () {
      if (!mounted) return;
      if (_shouldStillBeInteracting()) {
        // Still moving; we'll get rescheduled by later updates.
        return;
      }
      // Skip refine pass if the preview frame already converged — no
      // visible change would result from the extra CPU work.
      if (_isConverged) return;
      _renderRefine();
    });
  }

  void _setSlowModeActive(bool active) {
    if (_slowModeActive == active) return;
    if (mounted) {
      setState(() {
        _slowModeActive = active;
      });
    } else {
      _slowModeActive = active;
    }
    widget.onSlowModeActiveChanged?.call(active);
  }

  static const int _tileSize = 96;

  List<(int x0, int y0, int w, int h)> _tileOrder({
    required int width,
    required int height,
  }) {
    final cols = (width / _tileSize).ceil();
    final rows = (height / _tileSize).ceil();

    final startX = (cols - 1) ~/ 2;
    final startY = (rows - 1) ~/ 2;

    final out = <(int, int, int, int)>[];
    final seen = List.generate(rows, (_) => List<bool>.filled(cols, false));

    void addTile(int tx, int ty) {
      if (tx < 0 || ty < 0 || tx >= cols || ty >= rows) return;
      if (seen[ty][tx]) return;
      seen[ty][tx] = true;

      final x0 = tx * _tileSize;
      final y0 = ty * _tileSize;
      final w = (x0 + _tileSize <= width) ? _tileSize : (width - x0);
      final h = (y0 + _tileSize <= height) ? _tileSize : (height - y0);
      if (w <= 0 || h <= 0) return;
      out.add((x0, y0, w, h));
    }

    // Classic spiral walk over the tile grid.
    int x = startX;
    int y = startY;
    int dx = 1;
    int dy = 0;
    int segmentLen = 1;
    int segmentPassed = 0;
    int segments = 0;

    while (out.length < cols * rows) {
      addTile(x, y);
      x += dx;
      y += dy;
      segmentPassed++;

      if (segmentPassed == segmentLen) {
        segmentPassed = 0;
        // rotate right
        final ndx = -dy;
        final ndy = dx;
        dx = ndx;
        dy = ndy;
        segments++;
        if (segments % 2 == 0) segmentLen++;
      }

      // Safety: break if we somehow loop forever.
      if (segmentLen > cols + rows + 4) break;
    }

    return out;
  }

  Future<CpuRenderFrame> _renderFrameTiled({
    required int width,
    required int height,
    required int iterations,
    required double bailout,
    required Vector2 juliaC,
    required int sampleCount,
    required int job,
    required Duration? maxTime,
    required ValueChanged<ui.Image> onPartial,
  }) async {
    final full = Uint8List(width * height * 4);
    // Start with an opaque background so partial-tile progressive updates don't
    // look like "missing" regions (transparent pixels showing the UI behind).
    for (int i = 3; i < full.length; i += 4) {
      full[i] = 255;
    }
    final started = DateTime.now();

    int tilesDone = 0;
    DateTime lastUpdate = DateTime.fromMillisecondsSinceEpoch(0);

    for (final tile in _tileOrder(width: width, height: height)) {
      if (!mounted || job != _job) break;

      if (maxTime != null && DateTime.now().difference(started) > maxTime) {
        break;
      }

      final req = CpuTileRenderRequest(
        moduleId: widget.module.id,
        panX: widget.state.view.pan.x,
        panY: widget.state.view.pan.y,
        zoom: widget.state.view.zoom,
        iterations: iterations,
        bailout: bailout,
        juliaCX: juliaC.x,
        juliaCY: juliaC.y,
        fullWidth: width,
        fullHeight: height,
        x0: tile.$1,
        y0: tile.$2,
        w: tile.$3,
        h: tile.$4,
        sampleCount: sampleCount,
      );

      final worker = _worker;
      if (worker == null)
        return CpuRenderFrame(rgba: full, width: width, height: height);
      final resp = await worker.renderTile(req);

      // Blit tile into full buffer.
      for (int ty = 0; ty < resp.h; ty++) {
        final dstRow = ((resp.y0 + ty) * width + resp.x0) * 4;
        final srcRow = (ty * resp.w) * 4;
        full.setRange(
          dstRow,
          dstRow + resp.w * 4,
          resp.rgba,
          srcRow,
        );
      }

      tilesDone++;

      // Progressive UI update (throttled).
      final now = DateTime.now();
      final shouldUpdate = tilesDone == 1 ||
          tilesDone % 6 == 0 ||
          now.difference(lastUpdate) > const Duration(milliseconds: 80);
      if (shouldUpdate) {
        lastUpdate = now;
        final img =
            await CpuRenderFrame(rgba: full, width: width, height: height)
                .toImage();
        if (!mounted || job != _job) break;
        onPartial(img);
      }
    }

    return CpuRenderFrame(rgba: full, width: width, height: height);
  }

  Future<void> _renderPass({
    required double resolutionScale,
    required int sampleCount,
    Duration? maxTime,
    bool isPreview = false,
  }) async {
    final int job = ++_job;
    try {
      final baseIterations = readInt(widget.state.params, 'iterations', 220);
      final maxIterations = _iterationMaxForModule();
      final control = cpuControlScalarForModule(
        widget.module.id,
        widget.state.params,
      );
      final juliaC = cpuJuliaCForModule(widget.module.id, widget.state.params);

      // Increase iteration budget as zoom increases to avoid blotchy boundaries.
      final iterations = CpuIterationBudget.forZoom(
        baseIterations: baseIterations,
        maxIterations: maxIterations,
        zoom: widget.state.view.zoom,
      );

      final resolution = CpuRenderResolution.forPass(
        targetWidth: widget.width,
        targetHeight: widget.height,
        resolutionScale: resolutionScale,
      );
      final w = resolution.width;
      final h = resolution.height;

      var frame = await _renderFrameTiled(
        width: w,
        height: h,
        iterations: iterations,
        bailout: control,
        juliaC: juliaC,
        sampleCount: sampleCount,
        job: job,
        maxTime: maxTime,
        onPartial: (img) {
          if (!mounted || job != _job) return;
          final oldImage = _image;
          setState(() {
            _image = img;
            _error = null;
          });
          oldImage?.dispose();
          widget.onPartial?.call();
        },
      );

      // Ensure user always sees something.
      if (_isNearlyBlack(frame.rgba)) {
        final fallback = _fallbackView(widget.module);
        final req = CpuTileRenderRequest(
          moduleId: widget.module.id,
          panX: fallback.$1.x,
          panY: fallback.$1.y,
          zoom: fallback.$2,
          iterations: iterations,
          bailout: control,
          juliaCX: juliaC.x,
          juliaCY: juliaC.y,
          fullWidth: w,
          fullHeight: h,
          x0: 0,
          y0: 0,
          w: w,
          h: h,
          sampleCount: 1,
        );
        final worker = _worker;
        if (worker != null) {
          final resp = await worker.renderTile(req);
          frame = CpuRenderFrame(rgba: resp.rgba, width: w, height: h);
        }
      }

      final img = await frame.toImage();

      if (isPreview) {
        // Always run convergence check after preview pass.
        // On first frame _checkConvergence stores the buffer and returns;
        // on subsequent frames it compares and updates _isConverged.
        _checkConvergence(frame.rgba, frame.width, frame.height, iterations);

        // Optional validation only in debug builds.
        RenderCheckResult? validation;
        if (kDebugMode) {
          final probe = await _renderFrameTiled(
            width: w,
            height: h,
            iterations: iterations + 16,
            bailout: control,
            juliaC: juliaC,
            sampleCount: 1,
            job: job,
            maxTime: null,
            onPartial: (_) {},
          );
          validation = validateRenderPair(
            frameA: frame.rgba,
            frameB: probe.rgba,
            width: frame.width,
            height: frame.height,
          );
          debugPrint(validation.summary('cpu'));
        }

        if (!mounted || job != _job) return;
        final oldImage = _image;
        setState(() {
          _image = img;
          _error = null;
          _lastValidation = validation;
        });
        oldImage?.dispose();
      } else {
        // Refine pass completion.
        if (!mounted || job != _job) return;
        final oldImage = _image;
        setState(() {
          _image = img;
          _error = null;
          _slowModeRow = null;
          _slowModeTotal = null;
        });
        oldImage?.dispose();

        // Start slow mode after refine completes.
        _renderSlowMode();
      }
    } catch (e) {
      if (!mounted || job != _job) return;
      final oldImage = _image;
      setState(() {
        _image = null;
        _error = e;
      });
      oldImage?.dispose();
    }
  }

  Future<void> _renderPreview() => _renderPass(
        resolutionScale: 0.8,
        sampleCount: 1,
        maxTime: const Duration(milliseconds: 140),
        isPreview: true,
      );

  Future<void> _renderRefine() => _renderPass(
        resolutionScale: 1.0,
        sampleCount: 4,
        maxTime: null,
        isPreview: false,
      );

  Future<void> _renderSlowMode() async {
    final int job = ++_job;
    _setSlowModeActive(true);

    try {
      final resolution = CpuRenderResolution.forSlowMode(
        targetWidth: widget.width,
        targetHeight: widget.height,
      );
      final w = resolution.width;
      final h = resolution.height;
      final buffer = Uint8List(w * h * 4);
      for (int i = 3; i < buffer.length; i += 4) {
        buffer[i] = 255;
      }

      final baseIterations = readInt(widget.state.params, 'iterations', 220);
      final maxIterations = _iterationMaxForModule();
      final control = cpuControlScalarForModule(
        widget.module.id,
        widget.state.params,
      );
      final juliaC = cpuJuliaCForModule(widget.module.id, widget.state.params);
      final iterations = CpuIterationBudget.forZoom(
        baseIterations: baseIterations,
        maxIterations: maxIterations,
        zoom: widget.state.view.zoom,
      );

      for (int row = 0; row < h; row++) {
        if (!mounted || job != _job) {
          _setSlowModeActive(false);
          return;
        }

        final req = CpuTileRenderRequest(
          moduleId: widget.module.id,
          panX: widget.state.view.pan.x,
          panY: widget.state.view.pan.y,
          zoom: widget.state.view.zoom,
          iterations: iterations,
          bailout: control,
          juliaCX: juliaC.x,
          juliaCY: juliaC.y,
          fullWidth: w,
          fullHeight: h,
          x0: 0,
          y0: row,
          w: w,
          h: 1,
          sampleCount: 4,
        );

        final worker = _worker;
        if (worker == null) {
          _setSlowModeActive(false);
          return;
        }
        final resp = await worker.renderTile(req);

        final dstOffset = row * w * 4;
        buffer.setRange(dstOffset, dstOffset + w * 4, resp.rgba);

        if (row % 8 == 0 || row == h - 1) {
          final img =
              await CpuRenderFrame(rgba: buffer, width: w, height: h).toImage();
          if (!mounted || job != _job) {
            _setSlowModeActive(false);
            return;
          }
          final oldImage = _image;
          setState(() {
            _image = img;
            _slowModeRow = row;
            _slowModeTotal = h;
            _error = null;
          });
          oldImage?.dispose();
          widget.onPartial?.call();
        }
      }

      if (mounted && job == _job) {
        setState(() {
          _slowModeRow = null;
          _slowModeTotal = null;
        });
      }
      _setSlowModeActive(false);
    } catch (e) {
      _setSlowModeActive(false);
      if (mounted) {
        setState(() {
          _error = e;
        });
      }
    }
  }

  bool _isNearlyBlack(Uint8List rgba) {
    final totalPixels = rgba.length ~/ 4;
    final threshold = (totalPixels * 0.005).ceil();
    int nonBlack = 0;
    for (int i = 0; i < rgba.length; i += 4) {
      if (rgba[i] > 8 || rgba[i + 1] > 8 || rgba[i + 2] > 8) {
        nonBlack++;
        if (nonBlack >= threshold) return false;
      }
    }
    return true;
  }

  (Vector2, double) _fallbackView(FractalModule module) {
    // Prefer each module's curated default preset (stable fallback baseline).
    final view = module.defaultPreset.view;
    final zoom = view.zoom > 0 ? view.zoom : 1.0;
    return (Vector2(view.pan.x, view.pan.y), zoom);
  }

  int _iterationMaxForModule() {
    for (final param in widget.module.parameters) {
      if (param.id == 'iterations') {
        return param.max.round();
      }
    }
    return 5000;
  }

  @override
  Widget build(BuildContext context) {
    if (_error != null) {
      return Center(
        child: Text(
          'CPU render failed: $_error',
          style: const TextStyle(color: Colors.redAccent),
          textAlign: TextAlign.center,
        ),
      );
    }
    final img = _image;
    if (img == null) {
      return const Center(child: CircularProgressIndicator());
    }
    return LayoutBuilder(
      builder: (context, constraints) {
        final height =
            constraints.maxHeight.isFinite ? constraints.maxHeight : 400.0;

        return Stack(
          children: [
            Positioned.fill(
              child: FittedBox(
                fit: BoxFit.cover,
                child: SizedBox(
                  width: img.width.toDouble(),
                  height: img.height.toDouble(),
                  child: RawImage(image: img, filterQuality: FilterQuality.low),
                ),
              ),
            ),
            if (_slowModeRow != null && _slowModeTotal != null)
              Positioned(
                top: (_slowModeRow! / _slowModeTotal! * height),
                left: 0,
                right: 0,
                height: 2,
                child: Container(color: Colors.cyan.withValues(alpha: 0.6)),
              ),
            if (_slowModeActive)
              Positioned(
                top: 8,
                left: 8,
                child: Container(
                  padding:
                      const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
                  decoration: BoxDecoration(
                    color: Colors.black.withValues(alpha: 0.68),
                    borderRadius: BorderRadius.circular(8),
                    border:
                        Border.all(color: Colors.cyan.withValues(alpha: 0.7)),
                  ),
                  child: const Text(
                    'High Res ✦',
                    style: TextStyle(
                      color: Colors.cyan,
                      fontSize: 11,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                ),
              ),
            if (kDebugMode && _lastValidation != null)
              Positioned(
                left: 10,
                top: 92,
                child: Container(
                  padding:
                      const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
                  decoration: BoxDecoration(
                    color: Colors.black.withValues(alpha: 0.7),
                    borderRadius: BorderRadius.circular(8),
                  ),
                  child: Text(
                    'CPU check: ${_lastValidation!.pass ? 'PASS' : 'WARN'} ratio=${_lastValidation!.nonBlackRatio.toStringAsFixed(3)}',
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 11,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                ),
              ),
          ],
        );
      },
    );
  }
}

class CpuRenderFrame {
  final Uint8List rgba;
  final int width;
  final int height;

  const CpuRenderFrame({
    required this.rgba,
    required this.width,
    required this.height,
  });

  Future<ui.Image> toImage() async {
    final c = Completer<ui.Image>();
    // ignore: deprecated_member_use
    ui.decodeImageFromPixels(
      rgba,
      width,
      height,
      ui.PixelFormat.rgba8888,
      (img) => c.complete(img),
    );
    return c.future;
  }
}

Future<CpuRenderFrame> renderCpuFrame({
  required String moduleId,
  required Vector2 viewPan,
  required double viewZoom,
  required int iterations,
  required double bailout,
  required Vector2 juliaC,
  required int width,
  required int height,
  int sampleCount = 4,
}) async {
  final bytes = renderCpuRectRgba(
    moduleId: moduleId,
    panX: viewPan.x,
    panY: viewPan.y,
    zoom: viewZoom,
    iterations: iterations,
    bailout: bailout,
    juliaCX: juliaC.x,
    juliaCY: juliaC.y,
    fullWidth: width,
    fullHeight: height,
    x0: 0,
    y0: 0,
    w: width,
    h: height,
    sampleCount: sampleCount,
  );

  return CpuRenderFrame(rgba: bytes, width: width, height: height);
}

/// Iteration/escape buffer (palette-independent) for correctness + quality metrics.
///
/// Returns a [Uint16List] with one entry per pixel:
/// - 0..iterations: integer escape iteration count
/// - iterations means "inside" (did not escape)
Future<Uint16List?> renderCpuIterationBuffer({
  required String moduleId,
  required Vector2 viewPan,
  required double viewZoom,
  required int iterations,
  required double bailout,
  required Vector2 juliaC,
  required int width,
  required int height,
}) async {
  CpuRenderDimensions(width: width, height: height).validate();

  final viewport = CpuViewportMapping(
    viewPan: viewPan,
    viewZoom: viewZoom,
    width: width,
    height: height,
  );

  final itFn = proxyIteratorForModule(moduleId);

  final out = Uint16List(width * height);
  for (int y = 0; y < height; y++) {
    final ny = viewport.normalizedPixel(y, height);
    for (int x = 0; x < width; x++) {
      final nx = viewport.normalizedPixel(x, width);
      final c = viewport.coordinate(nx: nx, ny: ny);
      final r = itFn(c.$1, c.$2, iterations, bailout, juliaC);
      out[y * width + x] = r.it.clamp(0, iterations);
    }
  }

  return out;
}

/// Lower is smoother (less grain).
double computeGrainScore(Uint8List rgba, int width, int height) {
  if (width < 2 || height < 2) return 0;
  double sum = 0;
  int count = 0;

  int at(int x, int y, int c) => rgba[(y * width + x) * 4 + c];

  for (int y = 0; y < height - 1; y++) {
    for (int x = 0; x < width - 1; x++) {
      for (int c = 0; c < 3; c++) {
        final v = at(x, y, c);
        sum += (v - at(x + 1, y, c)).abs();
        sum += (v - at(x, y + 1, c)).abs();
        count += 2;
      }
    }
  }
  return sum / count;
}

/// Module-aware control scalar for CPU formulas.
///
/// Most formulas use `bailout`; Nova uses `relaxation` in that slot.
double cpuControlScalarForModule(String moduleId, Map<String, Object> params) {
  if (moduleId == 'nova') {
    return readDouble(params, 'relaxation', 1.0);
  }
  return readDouble(params, 'bailout', 4.0);
}

/// Module-aware complex parameter passed to CPU formulas.
///
/// Julia-family formulas read `juliaC*`; Phoenix reads `phoenixC*`.
Vector2 cpuJuliaCForModule(String moduleId, Map<String, Object> params) {
  if (moduleId == 'phoenix') {
    final x = readDouble(params, 'phoenixCReal', 0.5667);
    final y = readDouble(params, 'phoenixCImag', 0.0);
    return Vector2(x, y);
  }

  final x = readDouble(params, 'juliaCReal', -0.8);
  final y = readDouble(params, 'juliaCImag', 0.156);
  return Vector2(x, y);
}

