// CPU formula implementations for escape-time catalog modules.
//
// NOTE: This file mirrors the core recurrence / iteration logic from the
// corresponding GPU shaders under shaders/*.frag. The CPU path is a
// correctness-oriented fallback (used when GPU shaders are unavailable).

import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

typedef CpuFormula = (double r, double g, double b) Function(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
);

typedef CpuFormulaPlanePoint = ({double x, double y});

/// Maps app/display coordinates to the Burning Ship shader parameter plane.
///
/// The GPU shader flips Y so the ship is upright in screen space. The base
/// CPU color formula and scalar iterator must share this before recurrence.
CpuFormulaPlanePoint cpuBurningShipParameterPlanePoint(double x, double y) {
  return (x: x, y: -y);
}

