(double r, double g, double b) _cpu_collatz(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Ported from shaders/escape_time_family/transcendental_maps/discrete_chaos/collatz_gpu.frag
  double zx = x;
  double zy = y;
  final bailout2 = bailout * bailout;
