  for (int j = 0; j < iterations; j++) {
    final tx = _clamp(math.tan(3.0 * zy), -50.0, 50.0);
    final ty = _clamp(math.tan(3.0 * zx), -50.0, 50.0);

    final xn = zx - h * math.sin(zy + tx);
    final yn = zy - h * math.sin(zx + ty);
    zx = xn;
    zy = yn;

    if (zx * zx + zy * zy > 64.0) {
      it = j;
