import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';

/// Generates one randomized value for a fractal parameter schema.
///
/// This pure helper keeps the controller's randomization data flow visible and
/// replayable in tests without depending on FractalController state. Returned
/// values are normalized through the same schema contract used for presets,
/// replayed state, and direct UI updates.
Object randomFractalParamValue(FractalParameter param, Random random) {
  switch (param.type) {
    case FractalParamType.float:
      final raw = param.min + random.nextDouble() * (param.max - param.min);
      return normalizeFractalParamValue(
        param,
        roundFractalParamValueToStep(raw, param.step),
      );
    case FractalParamType.integer:
      final bounds = FractalNumericParamBounds.fromSchema(param);
      assert(
        bounds.containsInteger,
        'integer parameter bounds must include at least one integer value',
      );
      if (!bounds.containsInteger) {
        return normalizeFractalParamValue(param, param.defaultValue);
      }
      final min = bounds.min.ceil();
      final max = bounds.max.floor();
      return normalizeFractalParamValue(
        param,
        min + random.nextInt(max - min + 1),
      );
    case FractalParamType.enumeration:
      if (param.options.isNotEmpty) {
        final choice = param.options[random.nextInt(param.options.length)];
        return choice.value;
      }
      return param.defaultValue;
    case FractalParamType.boolean:
      return random.nextBool();
  }
}

/// Replayable decision for snapping a randomized float to slider precision.
///
/// Parameter schemas are hand-authored across a large catalog. A malformed
/// non-finite step or raw value must not crash randomization before the shared
/// schema normalizer gets a chance to clamp/fallback the value.
final class FractalParamStepSnapPlan {
  final double inputValue;
  final double step;
  final double value;
  final bool appliedStep;

  const FractalParamStepSnapPlan._({
    required this.inputValue,
    required this.step,
    required this.value,
    required this.appliedStep,
  });

  factory FractalParamStepSnapPlan.fromValue({
    required double value,
    required double step,
  }) {
    if (!value.isFinite || !step.isFinite || step <= 0.0) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    final snapped = (value / step).round() * step;
    if (!snapped.isFinite) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    return FractalParamStepSnapPlan._(
      inputValue: value,
      step: step,
      value: double.parse(snapped.toStringAsFixed(6)),
      appliedStep: true,
    );
  }
}

/// Snaps float randomization to slider step precision while avoiding typical
/// binary floating-point display noise.
double roundFractalParamValueToStep(double value, double step) {
  return FractalParamStepSnapPlan.fromValue(value: value, step: step).value;
}

/// Replayable kaleidoscope effect state owned by [FractalController].
///
/// Some catalog modules are kaleidoscope-specific and temporarily force the
/// global kaleidoscope canvas effect on with module defaults. Keeping the
/// previous user-controlled effect state separate from the forced module state
/// prevents module switches from leaking kaleidoscope settings into unrelated
/// fractals.
final class FractalKaleidoscopeState {
  static const int defaultSectors = 8;
  static const int forcedModuleSectors = 16;
  static const int defaultMirrorMode = 0;
  static const int forcedModuleMirrorMode = 3;

  final bool enabled;
  final int sectors;
  final bool mirror;
  final double rotation;
  final int mirrorMode;

  const FractalKaleidoscopeState({
    required this.enabled,
    required this.sectors,
    required this.mirror,
    required this.rotation,
    required this.mirrorMode,
  });

  const FractalKaleidoscopeState.defaults()
      : enabled = false,
        sectors = defaultSectors,
        mirror = true,
        rotation = 0.0,
        mirrorMode = defaultMirrorMode;

  FractalKaleidoscopeState copyWith({
    bool? enabled,
    int? sectors,
    bool? mirror,
    double? rotation,
    int? mirrorMode,
  }) {
    return FractalKaleidoscopeState(
      enabled: enabled ?? this.enabled,
      sectors: sectors ?? this.sectors,
      mirror: mirror ?? this.mirror,
      rotation: rotation ?? this.rotation,
      mirrorMode: mirrorMode ?? this.mirrorMode,
    );
  }
}

/// Result of applying module-specific kaleidoscope defaults.
final class FractalKaleidoscopeModuleTransition {
  final FractalKaleidoscopeState effective;
  final FractalKaleidoscopeState? restoreAfterForcedModule;

  const FractalKaleidoscopeModuleTransition({
    required this.effective,
    required this.restoreAfterForcedModule,
  });
}

/// Pure module-switch policy for dedicated kaleidoscope catalog modules.
///
/// Only modules whose IDs use the catalog kaleidoscope prefix force the global
/// kaleidoscope canvas effect. Other fractals may include "kaleidoscope" in
/// their own shader/name without needing the global post-effect defaults.
final class FractalKaleidoscopeModulePolicy {
  static const String forcedModuleIdPrefix = 'kaleidoscope_';

  const FractalKaleidoscopeModulePolicy._();

  static bool isForcedModuleId(String moduleId) =>
      moduleId.startsWith(forcedModuleIdPrefix);

  static FractalKaleidoscopeModuleTransition transitionForModule({
    required String moduleId,
    required FractalKaleidoscopeState current,
    required FractalKaleidoscopeState? restoreAfterForcedModule,
  }) {
    if (isForcedModuleId(moduleId)) {
      return FractalKaleidoscopeModuleTransition(
        effective: current.copyWith(
          enabled: true,
          sectors: FractalKaleidoscopeState.forcedModuleSectors,
          mirrorMode: FractalKaleidoscopeState.forcedModuleMirrorMode,
        ),
        restoreAfterForcedModule: restoreAfterForcedModule ?? current,
      );
    }

    if (restoreAfterForcedModule != null) {
      return FractalKaleidoscopeModuleTransition(
        effective: restoreAfterForcedModule,
        restoreAfterForcedModule: null,
      );
    }

    return FractalKaleidoscopeModuleTransition(
      effective: current,
      restoreAfterForcedModule: null,
    );
  }
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Read-only snapshot of controller parameters for public exposure.
///
/// [FractalController] owns parameter validation and listener notification.
/// Returning the backing map lets callers mutate controller state without
/// normalization or notifications, so public reads get a defensive top-level
/// copy instead.
Map<String, Object> snapshotFractalControllerParams(
  Map<String, Object> params,
) {
  return Map<String, Object>.unmodifiable(params);
}

/// Defensive copy of controller view state for public exposure.
///
/// [FractalViewState] is immutable by field assignment, but its vector fields
/// are mutable. Clone vectors at the controller boundary so external reads
/// cannot mutate pan/rotation without going through controller update methods.
FractalViewState snapshotFractalControllerView(FractalViewState view) {
  return FractalViewState(
    pan: Vector2.copy(view.pan),
    zoom: view.zoom,
    rotation: Vector3.copy(view.rotation),
  );
}

import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

/// Provenance for the custom export dimension that wins resolution.
enum CustomExportDimensionSource {
  fieldText,
  currentValue,
  fallback,
}

/// Replayable result of resolving one custom export dimension.
///
/// The export model clamps target dimensions later, but the sheet summary and
/// submission payload read [ExportOptions.customWidth]/customHeight directly.
/// Keep that boundary normalized too so all export dimension paths share the
/// same safety contract.
final class CustomExportDimensionResolution {
  const CustomExportDimensionResolution({
    required this.value,
    required this.source,
    required this.wasClamped,
  });

  final int value;
  final CustomExportDimensionSource source;
  final bool wasClamped;
}

CustomExportDimensionResolution resolveCustomExportDimensionPlan({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  return _normalizeCustomExportDimension(
        parsed,
        source: CustomExportDimensionSource.fieldText,
      ) ??
      _normalizeCustomExportDimension(
        currentValue,
        source: CustomExportDimensionSource.currentValue,
      ) ??
      _normalizeFallbackCustomExportDimension(fallback);
}

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  return resolveCustomExportDimensionPlan(
    fieldText: fieldText,
    currentValue: currentValue,
    fallback: fallback,
  ).value;
}

CustomExportDimensionResolution? _normalizeCustomExportDimension(
  int? value, {
  required CustomExportDimensionSource source,
}) {
  final normalized = ExportDimensionPolicy.positiveCustomDimension(value);
  if (normalized == null) return null;

  return CustomExportDimensionResolution(
    value: normalized,
    source: source,
    wasClamped: normalized != value,
  );
}

CustomExportDimensionResolution _normalizeFallbackCustomExportDimension(
  int fallback,
) {
  final safeFallback = fallback > 0 ? fallback : 1;
  final normalized = ExportDimensionPolicy.positiveCustomDimension(
    safeFallback,
  )!;

  return CustomExportDimensionResolution(
    value: normalized,
    source: CustomExportDimensionSource.fallback,
    wasClamped: normalized != fallback,
  );
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/features/export/custom_export_dimensions.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('resolveCustomExportDimension', () {
    test('uses positive field text before current value or fallback', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '2048',
          currentValue: 1024,
          fallback: defaultCustomExportWidth,
        ),
        2048,
      );
    });

    test('falls back to current value when field text is invalid', () {
      expect(
        resolveCustomExportDimension(
          fieldText: 'not a number',
          currentValue: 1024,
          fallback: defaultCustomExportWidth,
        ),
        1024,
      );
    });

    test('normalizes oversized field text through export dimension policy', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '${1 << 40}',
          currentValue: null,
          fallback: defaultCustomExportWidth,
        ),
        ExportDimensionPolicy.maxPixelDimension,
      );
    });

    test('normalizes oversized current value fallback through policy', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '',
          currentValue: 1 << 40,
          fallback: defaultCustomExportWidth,
        ),
        ExportDimensionPolicy.maxPixelDimension,
      );
    });
  });

  group('resolveCustomExportDimensionPlan', () {
    test('exposes winning source and clamp provenance', () {
      final clampedField = resolveCustomExportDimensionPlan(
        fieldText: '${1 << 40}',
        currentValue: 1024,
        fallback: defaultCustomExportWidth,
      );
      final currentFallback = resolveCustomExportDimensionPlan(
        fieldText: '0',
        currentValue: 1024,
        fallback: defaultCustomExportWidth,
      );

      expect(clampedField.value, ExportDimensionPolicy.maxPixelDimension);
      expect(clampedField.source, CustomExportDimensionSource.fieldText);
      expect(clampedField.wasClamped, isTrue);
      expect(currentFallback.value, 1024);
      expect(currentFallback.source, CustomExportDimensionSource.currentValue);
      expect(currentFallback.wasClamped, isFalse);
    });
  });

  group('withResolvedCustomExportDimensions', () {
    test('stores normalized custom dimensions in the export payload', () {
      final resolved = withResolvedCustomExportDimensions(
        options: const ExportOptions(
          resolution: ExportResolution.custom,
          customWidth: 1 << 40,
          customHeight: 720,
        ),
        widthText: '',
        heightText: '${1 << 35}',
      );

      expect(resolved.customWidth, ExportDimensionPolicy.maxPixelDimension);
      expect(resolved.customHeight, ExportDimensionPolicy.maxPixelDimension);
    });
  });
}

