class BatchExportItemResult {
  final FractalPreset preset;
  final File file;
  final int index;

  const BatchExportItemResult({
    required this.preset,
    required this.file,
    required this.index,
  });
}

class BatchExportResult {
  final Directory directory;
  final List<BatchExportItemResult> items;
  final File? contactSheet;

  const BatchExportResult({
    required this.directory,
    required this.items,
    this.contactSheet,
  });
}

class BatchExportPlanEntry {
  final FractalPreset preset;
  final int sourceIndex;
  final int exportIndex;

  const BatchExportPlanEntry({
    required this.preset,
    required this.sourceIndex,
    required this.exportIndex,
  });
}

class BatchExportPlan {
  final List<BatchExportPlanEntry> entries;

  const BatchExportPlan._(this.entries);

  int get total => entries.length;

  static BatchExportPlan forModule({
    required String moduleId,
    required List<FractalPreset> presets,
  }) {
    final entries = <BatchExportPlanEntry>[];
    for (var sourceIndex = 0; sourceIndex < presets.length; sourceIndex++) {
      final preset = presets[sourceIndex];
      if (preset.moduleId != moduleId) continue;
      entries.add(
        BatchExportPlanEntry(
          preset: preset,
          sourceIndex: sourceIndex,
          exportIndex: entries.length,
        ),
      );
    }
    return BatchExportPlan._(List.unmodifiable(entries));
  }
}

/// Replayable capture options and output path for one batch item.
///
/// Batch export goes through the same encoder as single-image export, where
/// WebP currently resolves to PNG. Keeping the effective format in this plan
/// prevents PNG bytes from being written to a stale `.webp` filename and keeps
/// metadata timestamps tied to the injected batch clock.
class BatchExportCapturePlan {
  final ExportOptions captureOptions;
  final String filename;
  final ExportMetadata? metadata;

  const BatchExportCapturePlan({
    required this.captureOptions,
    required this.filename,
    this.metadata,
  });

  factory BatchExportCapturePlan.forEntry({
    required BatchExportPlanEntry entry,
    required ExportOptions baseOptions,
    required ExportFormat effectiveFormat,
    required String moduleId,
    required String moduleDisplayName,
    required Map<String, Object> parameters,
    required DateTime createdAt,
  }) {
    final preset = entry.preset;
    final metadata = baseOptions.embedMetadata
        ? ExportMetadata(
            title: preset.name,
            description: 'Preset export from $moduleDisplayName',
            fractalType: moduleId,
            parameters: parameters,
            createdAt: createdAt,
          )
        : null;

    return BatchExportCapturePlan(
      captureOptions: baseOptions.copyWith(
        format: effectiveFormat,
        metadata: metadata,
      ),
      filename: BatchExportPresetFilename(
        moduleId: moduleId,
        index: entry.exportIndex,
        presetName: preset.name,
        format: effectiveFormat,
      ).value,
      metadata: metadata,
    );
  }
}

/// Replayable filename contract for one batch preset image.
class BatchExportPresetFilename {
  final String moduleId;
  final int index;
  final String presetName;
  final ExportFormat format;

  const BatchExportPresetFilename({
    required this.moduleId,
    required this.index,
    required this.presetName,
    required this.format,
  });

  String get value {
    final idx = (index + 1).toString().padLeft(3, '0');
    final slug = _safeBatchExportSlug(presetName);
    return '${_safeBatchExportSlug(moduleId)}_${idx}_$slug.${format.extension}';
  }
}

String _safeBatchExportSlug(String input) {
  final trimmed = input.trim().toLowerCase();
  final replaced = trimmed
      .replaceAll(RegExp(r'[^a-z0-9]+'), '_')
      .replaceAll(RegExp(r'_+'), '_')
      .replaceAll(RegExp(r'^_'), '')
      .replaceAll(RegExp(r'_$'), '');
  return replaced.isEmpty ? 'untitled' : replaced;
}

/// Clock contract for replayable batch export directory naming.
abstract class BatchExportClock {
  DateTime now();
}

class SystemBatchExportClock implements BatchExportClock {
  const SystemBatchExportClock();

  @override
  DateTime now() => DateTime.now();
}

/// Frame-pump contract for replayable batch export tests.
abstract class BatchExportFramePump {
  Future<void> waitForPresetRender();
}

class WidgetsBindingBatchExportFramePump implements BatchExportFramePump {
  const WidgetsBindingBatchExportFramePump();

  @override
  Future<void> waitForPresetRender() async {
    await WidgetsBinding.instance.endOfFrame;
    await WidgetsBinding.instance.endOfFrame;
  }
}

class BatchExportService {
  final ExportService _exportService;
  final BatchExportClock _clock;
  final BatchExportFramePump _framePump;

  const BatchExportService({
    ExportService exportService = const ExportService(),
    BatchExportClock clock = const SystemBatchExportClock(),
    BatchExportFramePump framePump = const WidgetsBindingBatchExportFramePump(),
  })  : _exportService = exportService,
        _clock = clock,
        _framePump = framePump;

  Future<BatchExportResult> exportPresets({
    required GlobalKey boundaryKey,
    required Future<void> Function(FractalPreset preset) applyPreset,
    required List<FractalPreset> presets,
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    required String moduleId,
    required String moduleDisplayName,
    required Map<String, Object> Function() currentParameters,
    required void Function(double overallProgress, String status)? onProgress,
    required void Function(BatchExportItemResult item)? onItemDone,
    required bool Function() isCancelled,
  }) async {
    if (kIsWeb) throw UnsupportedError('exportPresets is not supported on web');
    final directory = await _createBatchDirectory(moduleId: moduleId);
    final results = <BatchExportItemResult>[];
    final plan =
        BatchExportPlan.forModule(moduleId: moduleId, presets: presets);
    final effectiveFormat =
        _exportService.resolveEffectiveFormat(options.format);

    for (final entry in plan.entries) {
      if (isCancelled()) break;

      final preset = entry.preset;
      onProgress?.call(
        entry.exportIndex / plan.total,
        'Exporting ${entry.exportIndex + 1}/${plan.total}: ${preset.name}',
      );

      await applyPreset(preset);
      await _framePump.waitForPresetRender();

      final capturePlan = BatchExportCapturePlan.forEntry(
        entry: entry,
        baseOptions: options,
        effectiveFormat: effectiveFormat,
        moduleId: moduleId,
        moduleDisplayName: moduleDisplayName,
        parameters: options.embedMetadata
            ? Map<String, Object>.from(currentParameters())
            : const <String, Object>{},
        createdAt: _clock.now(),
      );

      final bytes = await _exportService.captureWithOptions(
        boundaryKey,
        options: capturePlan.captureOptions,
        screenWidth: screenWidth,
        screenHeight: screenHeight,
      );

      final file = File('${directory.path}/${capturePlan.filename}');
      await file.writeAsBytes(bytes, flush: true);

      final item = BatchExportItemResult(
        preset: preset,
        file: file,
        index: entry.exportIndex,
      );
      results.add(item);
      onItemDone?.call(item);
    }

    File? contactSheet;
    if (results.isNotEmpty && !isCancelled()) {
      onProgress?.call(0.95, 'Building contact sheet…');
      try {
        final pngBytes = await _buildContactSheet(
          results.map((e) => e.file).toList(),
          columns: 4,
          tileSize: 512,
          padding: 16,
        );
        final name = 'contact_sheet_${_safeBatchExportSlug(moduleId)}.png';
        final out = File('${directory.path}/$name');
        await out.writeAsBytes(pngBytes, flush: true);
        contactSheet = out;
      } catch (e) {
        if (kDebugMode) debugPrint('[FF] silent catch: $e');
      }
    }

    onProgress?.call(1.0, 'Done');
    return BatchExportResult(
        directory: directory, items: results, contactSheet: contactSheet);
  }

  Future<Directory> _createBatchDirectory({required String moduleId}) async {
    final base = await _exportService.getExportDirectory();
    final ts = _clock.now();
    final stamp =
        '${ts.year.toString().padLeft(4, '0')}${ts.month.toString().padLeft(2, '0')}${ts.day.toString().padLeft(2, '0')}_${ts.hour.toString().padLeft(2, '0')}${ts.minute.toString().padLeft(2, '0')}${ts.second.toString().padLeft(2, '0')}';
    final prefix =
        '${base.path}/batch_${_safeBatchExportSlug(moduleId)}_$stamp';

    for (var attempt = 1;; attempt++) {
      final suffix =
          attempt == 1 ? '' : '_${attempt.toString().padLeft(2, '0')}';
      final dir = Directory('$prefix$suffix');
      if (await dir.exists()) continue;
      await dir.create(recursive: true);
      return dir;
    }
  }

  Future<Uint8List> _buildContactSheet(
    List<File> files, {
    required int columns,
    required int tileSize,
    required int padding,
  }) async {
    final thumbs = <img.Image>[];
    for (final f in files) {
      final bytes = await f.readAsBytes();
      final decoded = img.decodeImage(bytes);
      if (decoded == null) continue;
      thumbs.add(img.copyResize(decoded,
          width: tileSize,
          height: tileSize,
          interpolation: img.Interpolation.cubic));
    }
    if (thumbs.isEmpty) throw StateError('No images');

    final cols = columns.clamp(1, 12);
    final rows = ((thumbs.length + cols - 1) / cols).floor();
    final width = padding + cols * (tileSize + padding);
    final height = padding + rows * (tileSize + padding);

    final sheet = img.Image(width: width, height: height, numChannels: 4);
    img.fill(sheet, color: img.ColorRgba8(12, 12, 12, 255));

    for (var i = 0; i < thumbs.length; i++) {
      final r = i ~/ cols;
      final c = i % cols;
      final x = padding + c * (tileSize + padding);
      final y = padding + r * (tileSize + padding);
      img.compositeImage(sheet, thumbs[i], dstX: x, dstY: y);
    }

    return Uint8List.fromList(img.encodePng(sheet, level: 6));
  }
}

// Tests for BatchExportService.
//
// Key constraint: exportPresets() calls WidgetsBinding.instance.endOfFrame
// for every preset that enters the loop body. That future only resolves when
// the Flutter test framework pumps a frame, which doesn't happen inside
// testWidgets/tester.runAsync reliably.
//
// Strategy:
//   - All exportPresets tests use plain test() with isCancelled:()=>true so
//     the loop guard fires before the body (and before endOfFrame is awaited).
//   - The empty-presets path also never reaches endOfFrame.
//   - Value-type tests (BatchExportItemResult, BatchExportResult, ExportOptions)
//     are pure synchronous tests.
import 'dart:io';
import 'dart:typed_data';
import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:path_provider_platform_interface/path_provider_platform_interface.dart';
import 'package:plugin_platform_interface/plugin_platform_interface.dart';
import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/services/batch_export_service.dart';
import 'package:flutter_fractals/core/services/export_service.dart';
import 'package:image/image.dart' as img;
import 'package:vector_math/vector_math.dart';

class _FakePathProviderPlatform extends Fake
    with MockPlatformInterfaceMixin
    implements PathProviderPlatform {
  final String tempDir;
  _FakePathProviderPlatform(this.tempDir);

  @override
  Future<String?> getApplicationDocumentsPath() async => tempDir;

  @override
  Future<String?> getTemporaryPath() async => tempDir;
}

/// Stub [ExportService] that resolves directory ops without platform channels.
/// captureWithOptions throws to make it obvious if a test accidentally reaches
/// the loop body.
class _StubExportService extends ExportService {
  final String basePath;

  const _StubExportService(this.basePath);

  @override
  Future<Directory> getExportDirectory() async {
    final dir = Directory('$basePath/exports');
    if (!await dir.exists()) await dir.create(recursive: true);
    return dir;
  }

  @override
  Future<Uint8List> captureWithOptions(
    GlobalKey boundaryKey, {
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    void Function(double)? onProgress,
  }) async {
    throw UnimplementedError(
        'captureWithOptions should not be reached in these tests');
  }
}

class _FixedBatchExportClock implements BatchExportClock {
  final DateTime value;

  const _FixedBatchExportClock(this.value);

  @override
  DateTime now() => value;
}

class _NoopBatchExportFramePump implements BatchExportFramePump {
  const _NoopBatchExportFramePump();

  @override
  Future<void> waitForPresetRender() async {}
}

class _CapturingExportService extends _StubExportService {
  final capturedOptions = <ExportOptions>[];

  _CapturingExportService(super.basePath);

  @override
  Future<Uint8List> captureWithOptions(
    GlobalKey boundaryKey, {
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    void Function(double)? onProgress,
  }) async {
    capturedOptions.add(options);
    final image = img.Image(width: 1, height: 1);
    img.fill(image, color: img.ColorRgb8(1, 2, 3));
    return Uint8List.fromList(img.encodePng(image));
  }
}

FractalPreset _makePreset(String name) => FractalPreset(
      id: name,
      moduleId: 'mandelbrot',
      name: name,
      params: const {},
      view: FractalViewState(
        pan: Vector2.zero(),
        zoom: 1.0,
        rotation: Vector3.zero(),
      ),
      createdAt: DateTime(2026, 1, 1),
    );

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  late Directory tmpDir;
  late _StubExportService stubService;
  late BatchExportService service;

  setUp(() async {
    tmpDir = await Directory.systemTemp.createTemp('batch_test_');
    PathProviderPlatform.instance = _FakePathProviderPlatform(tmpDir.path);
    stubService = _StubExportService(tmpDir.path);
    service = BatchExportService(exportService: stubService);
  });

  tearDown(() async {
    if (await tmpDir.exists()) await tmpDir.delete(recursive: true);
  });

  // ---------------------------------------------------------------------------
  // Construction
  // ---------------------------------------------------------------------------
  group('BatchExportService construction', () {
    test('can be created with default ExportService', () {
      const svc = BatchExportService();
      expect(svc, isNotNull);
    });

    test('can be created with custom ExportService', () {
      expect(service, isNotNull);
    });
  });

  // ---------------------------------------------------------------------------
  // Value types — pure synchronous
  // ---------------------------------------------------------------------------
  group('BatchExportItemResult', () {
    test('holds preset, file, and index correctly', () {
      final preset = _makePreset('My Preset');
      final file = File('/tmp/test.png');
      final item = BatchExportItemResult(preset: preset, file: file, index: 3);
      expect(item.preset.name, 'My Preset');
      expect(item.file.path, '/tmp/test.png');
      expect(item.index, 3);
    });

    test('index zero is valid', () {
      final item = BatchExportItemResult(
        preset: _makePreset('First'),
        file: File('/tmp/first.png'),
        index: 0,
      );
      expect(item.index, 0);
    });

    test('preset fields are accessible via item', () {
      final preset = _makePreset('Deep Zoom');
      final item = BatchExportItemResult(
        preset: preset,
        file: File('/tmp/deep.png'),
        index: 5,
      );
      expect(item.preset.id, 'Deep Zoom');
      expect(item.preset.moduleId, 'mandelbrot');
    });
  });

  group('BatchExportPlan', () {
    test('filters presets to the requested module before export', () {
      final plan = BatchExportPlan.forModule(
        moduleId: 'mandelbrot',
        presets: [
          _makePreset('Mandelbrot A'),
          _makePreset('Julia A').copyWith(moduleId: 'julia'),
          _makePreset('Mandelbrot B'),
        ],
      );

      expect(plan.entries.map((e) => e.preset.name), [
        'Mandelbrot A',
        'Mandelbrot B',
      ]);
      expect(plan.entries.map((e) => e.sourceIndex), [0, 2]);
      expect(plan.entries.map((e) => e.exportIndex), [0, 1]);
      expect(plan.total, 2);
    });
  });

  group('BatchExportResult', () {
    test('holds directory, items, and no contact sheet', () {
      final dir = Directory('/tmp/batch');
      final file = File('/tmp/batch/file.png');
      final item =
          BatchExportItemResult(preset: _makePreset('P'), file: file, index: 0);
      final result =
          BatchExportResult(directory: dir, items: [item], contactSheet: null);
      expect(result.directory.path, '/tmp/batch');
      expect(result.items, hasLength(1));
      expect(result.contactSheet, isNull);
    });

    test('contact sheet field can be populated', () {
      final result = BatchExportResult(
        directory: Directory('/tmp/batch'),
        items: const [],
        contactSheet: File('/tmp/batch/contact_sheet_mandelbrot.png'),
      );
      expect(result.contactSheet, isNotNull);
      expect(result.contactSheet!.path, endsWith('.png'));
    });

    test('empty items list is valid', () {
      final result = BatchExportResult(
        directory: Directory('/tmp/batch'),
        items: const [],
        contactSheet: null,
      );
      expect(result.items, isEmpty);
    });

    test('multiple items can be stored', () {
      final items = List.generate(
        5,
        (i) => BatchExportItemResult(
          preset: _makePreset('P$i'),
          file: File('/tmp/p$i.png'),
          index: i,
        ),
      );
      final result = BatchExportResult(
        directory: Directory('/tmp/batch'),
        items: items,
        contactSheet: null,
      );
      expect(result.items, hasLength(5));
      expect(result.items[2].index, 2);
      expect(result.items[4].preset.name, 'P4');
    });
  });

  // ---------------------------------------------------------------------------
  // exportPresets — cancellation before loop body
  // Uses plain test() so real async IO works without fake-async interference.
  // isCancelled always returns true so endOfFrame is never awaited.
  // ---------------------------------------------------------------------------
  group('BatchExportService.exportPresets cancellation before loop body', () {
    test('empty preset list returns empty result without reaching loop body',
        () async {
      final result = await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: const [],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => false,
      );

      expect(result.items, isEmpty);
      expect(result.contactSheet, isNull);
    });

    test('empty preset list: only final 1.0 progress call is made', () async {
      final progressValues = <double>[];

      await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: const [],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: (p, _) => progressValues.add(p),
        onItemDone: null,
        isCancelled: () => false,
      );

      expect(progressValues, equals([1.0]));
    });

    test('isCancelled=true: applyPreset is never called', () async {
      bool applyWasCalled = false;

      await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async => applyWasCalled = true,
        presets: [_makePreset('Alpha')],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => true,
      );

      expect(applyWasCalled, isFalse);
    });

    test('isCancelled=true: result has empty items and no contact sheet',
        () async {
      final result = await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: [_makePreset('Alpha'), _makePreset('Beta')],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => true,
      );

      expect(result.items, isEmpty);
      expect(result.contactSheet, isNull);
    });

    test('isCancelled=true with many presets: none are applied', () async {
      int applyCount = 0;

      await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async => applyCount++,
        presets: [_makePreset('A'), _makePreset('B'), _makePreset('C')],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => true,
      );

      expect(applyCount, 0);
    });

    test('isCancelled=true: onItemDone is never called', () async {
      int doneCalls = 0;

      await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: [_makePreset('X'), _makePreset('Y')],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: (_) => doneCalls++,
        isCancelled: () => true,
      );

      expect(doneCalls, 0);
    });

    test('result directory exists after empty export', () async {
      final result = await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: const [],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => false,
      );

      expect(await result.directory.exists(), isTrue);
    });

    test('batch directory name contains slugified moduleId', () async {
      final result = await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: const [],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'Mandelbrot Set',
        moduleDisplayName: 'Mandelbrot Set',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => false,
      );

      final dirName =
          result.directory.uri.pathSegments.where((s) => s.isNotEmpty).last;
      expect(dirName, contains('mandelbrot_set'));
    });

    test('batch directory name starts with "batch_"', () async {
      final result = await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: const [],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'julia',
        moduleDisplayName: 'Julia Set',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => false,
      );

      final dirName =
          result.directory.uri.pathSegments.where((s) => s.isNotEmpty).last;
      expect(dirName, startsWith('batch_'));
    });

    test('repeated exports in the same second get unique directories',
        () async {
      final fixedClock =
          _FixedBatchExportClock(DateTime(2026, 6, 1, 12, 34, 56));
      final deterministicService = BatchExportService(
        exportService: stubService,
        clock: fixedClock,
      );

      Future<BatchExportResult> runEmptyExport() {
        return deterministicService.exportPresets(
          boundaryKey: GlobalKey(),
          applyPreset: (_) async {},
          presets: const [],
          options: const ExportOptions(format: ExportFormat.png),
          screenWidth: 400,
          screenHeight: 800,
          moduleId: 'mandelbrot',
          moduleDisplayName: 'Mandelbrot',
          currentParameters: () => {},
          onProgress: null,
          onItemDone: null,
          isCancelled: () => false,
        );
      }

      final first = await runEmptyExport();
      final second = await runEmptyExport();

      expect(second.directory.path, isNot(first.directory.path));
      expect(second.directory.path, endsWith('_02'));
      expect(await first.directory.exists(), isTrue);
      expect(await second.directory.exists(), isTrue);
    });

    test('mixed-module presets are skipped before apply/export', () async {
      final capturingService = _CapturingExportService(tmpDir.path);
      final service = BatchExportService(
        exportService: capturingService,
        framePump: const _NoopBatchExportFramePump(),
      );
      final applied = <String>[];
      final done = <BatchExportItemResult>[];

      final result = await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (preset) async => applied.add(preset.name),
        presets: [
          _makePreset('Mandelbrot A'),
          _makePreset('Julia A').copyWith(moduleId: 'julia'),
          _makePreset('Mandelbrot B'),
        ],
        options: const ExportOptions(format: ExportFormat.png),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: done.add,
        isCancelled: () => false,
      );

      expect(applied, ['Mandelbrot A', 'Mandelbrot B']);
      expect(capturingService.capturedOptions, hasLength(2));
      expect(done.map((item) => item.index), [0, 1]);
      expect(result.items.map((item) => item.preset.name), [
        'Mandelbrot A',
        'Mandelbrot B',
      ]);
      expect(
        result.items.map((item) => item.file.path),
        everyElement(contains('mandelbrot')),
      );
    });

    test('batch metadata uses the injected clock for replayable timestamps',
        () async {
      final fixedTime = DateTime(2026, 6, 1, 12, 34, 56);
      final capturingService = _CapturingExportService(tmpDir.path);
      final service = BatchExportService(
        exportService: capturingService,
        clock: _FixedBatchExportClock(fixedTime),
        framePump: const _NoopBatchExportFramePump(),
      );

      await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: [_makePreset('Meta')],
        options: const ExportOptions(embedMetadata: true),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {'iterations': 100},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => false,
      );

      expect(capturingService.capturedOptions, hasLength(1));
      expect(capturingService.capturedOptions.single.metadata?.createdAt,
          fixedTime);
    });

    test('batch WebP fallback uses truthful PNG capture options and filenames',
        () async {
      final capturingService = _CapturingExportService(tmpDir.path);
      final service = BatchExportService(
        exportService: capturingService,
        framePump: const _NoopBatchExportFramePump(),
      );

      final result = await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: [_makePreset('WebP Fallback')],
        options: const ExportOptions(
          format: ExportFormat.webp,
          embedMetadata: false,
        ),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () => {},
        onProgress: null,
        onItemDone: null,
        isCancelled: () => false,
      );

      expect(capturingService.capturedOptions.single.format, ExportFormat.png);
      expect(result.items.single.file.path, endsWith('.png'));
      expect(result.items.single.file.path, isNot(endsWith('.webp')));
    });

    test('currentParameters is not called when isCancelled=true', () async {
      int paramCalls = 0;

      await service.exportPresets(
        boundaryKey: GlobalKey(),
        applyPreset: (_) async {},
        presets: [_makePreset('Meta')],
        options: const ExportOptions(embedMetadata: true),
        screenWidth: 400,
        screenHeight: 800,
        moduleId: 'mandelbrot',
        moduleDisplayName: 'Mandelbrot',
        currentParameters: () {
          paramCalls++;
          return {'iterations': 100};
        },
        onProgress: null,
        onItemDone: null,
        isCancelled: () => true,
      );

      expect(paramCalls, 0);
    });
  });

  // ---------------------------------------------------------------------------
  // ExportOptions model — pure synchronous unit tests
  // ---------------------------------------------------------------------------
  group('ExportOptions used in batch configuration', () {
    test('PNG format has correct extension', () {
      const opts = ExportOptions(format: ExportFormat.png);
      expect(opts.format.extension, 'png');
    });

    test('JPG format has correct extension', () {
      const opts = ExportOptions(format: ExportFormat.jpg);
      expect(opts.format.extension, 'jpg');
    });

    test('embedMetadata defaults to true', () {
      const opts = ExportOptions();
      expect(opts.embedMetadata, isTrue);
    });

    test('copyWith preserves unspecified fields', () {
      const original = ExportOptions(
        format: ExportFormat.png,
        quality: 90,
        embedMetadata: false,
      );
      final copied = original.copyWith(format: ExportFormat.jpg);
      expect(copied.format, ExportFormat.jpg);
      expect(copied.quality, 90);
      expect(copied.embedMetadata, isFalse);
    });

    test('getTargetDimensions returns fullHd dimensions', () {
      const opts = ExportOptions(resolution: ExportResolution.fullHd);
      expect(opts.getTargetDimensions(400, 300), (1920, 1080));
    });

    test('calculatePixelRatio clamps to 8.0 maximum', () {
      const opts = ExportOptions(resolution: ExportResolution.uhd4k);
      expect(opts.calculatePixelRatio(100, 100), 8.0);
    });

    test('ExportFormat.webp has webp extension', () {
      expect(ExportFormat.webp.extension, 'webp');
    });

    test('ExportResolution.instagram returns square dimensions', () {
      const opts = ExportOptions(resolution: ExportResolution.instagram);
      final dims = opts.getTargetDimensions(400, 400);
      expect(dims.$1, dims.$2); // square
    });
  });
}

